CREATE TABLE `profiles_infos` (
  `profile_code` bigint NOT NULL,
  `residence` varchar(255) DEFAULT NULL,
  `joiningdate` date DEFAULT NULL,
  `category` varchar(45) DEFAULT NULL,
  `nominate` varchar(45) DEFAULT NULL,
  `candidate` varchar(45) DEFAULT NULL,
  `nationality` varchar(45) DEFAULT NULL,
  `social_situation` varchar(45) DEFAULT NULL,
  `children` int DEFAULT NULL,
  `children_age` varchar(45) DEFAULT NULL,
  `education` varchar(45) DEFAULT NULL,
  `current_work` varchar(300) DEFAULT NULL,
  `word_about_association` text,
  `work_at_association` text,
  `identifiers` text,
  PRIMARY KEY (`profile_code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
