مستقر ينعم بالامن والايمان ويكون فيه الانسان مكرم ومعزز ومصان اي انسان كان ...','[{\"from_year\":\"2017\",\"to_year\":\"2020\",\"work_description\":\"منسقية المناطق + قسم قطاف - مركز الارشاد الطبي+ قسم الدعوة\"},{\"from_year\":\"2013\",\"to_year\":\"2017\",\"work_description\":\"الدعوة + دورات التدريب المهني + دائرة العمل الخيري \"},{\"from_year\":\"2009\",\"to_year\":\"2013\",\"work_description\":\"البدء من 2006 بداية متابعة انشاء وبناء المشروع حتى 2008 - من 2008 - 2009 التدريب المهني + العمل الخيري ( مساعدات + كفالات ايتام ...)\"},{\"from_year\":\"2005\",\"to_year\":\"2009\",\"work_description\":\"\"}]','الاخ المهندس جمال محيو والاخ المهندس وسيم مغربل والاخ ابو رامز جميل قاطرجي الاستاذ مصطفى الجردلي والاخ ابراهيم مسالخي الاخ المهندس محمد خضر ... وكثر من الاخوة الطراز الاول حفظهم الله جميعا '),(279,'بيروت-عفيف الطيبي','2005-01-01','الذكور',NULL,NULL,'لبنانية','متزوج',3,' 16-13-9','جامعي','مهندس ميكانيك في مكتبي الخاص',NULL,'[{\"from_year\":\"2017\",\"to_year\":\"2020\",\"work_description\":\"\"},{\"from_year\":\"2013\",\"to_year\":\"2017\",\"work_description\":\"نادي القبس ٣ سنوات\"},{\"from_year\":\"2009\",\"to_year\":\"2013\",\"work_description\":\"نادي القبس ٣ سنوات\"},{\"from_year\":\"2005\",\"to_year\":\"2009\",\"work_description\":\"\"}]','جمال محيو'),(280,'شحيم','2013-01-04','الذكور',NULL,NULL,'لبنانية','مطلق',1,'7','جامعي','موظف في شركة(بإنتظار اعادتنا للعمل بعد الإقفال منذ بدء الكورونا)','عمل منظم مع تخطيط','[{\"from_year\":\"2017\",\"to_year\":\"2020\",\"work_description\":\"حضور درس أسبوعي\"},{\"from_year\":\"2013\",\"to_year\":\"2017\",\"work_description\":\"حضور درس أسبوعي\"},{\"from_year\":\"2009\",\"to_year\":\"2013\",\"work_description\":\"\"},{\"from_year\":\"2005\",\"to_year\":\"2009\",\"work_description\":\"\"}]','جمال محيو، محي الدين قبرصلي.'),(282,'Chehim- jabal sweyd','2013-01-04','الذكور',NULL,NULL,'لبنانية','2',3,'11/10/5','جامعي','Consultant @ Khatib & Alami(Telecom)','منظمين، بارك الله بجهودكم','[{\"from_year\":\"2017\",\"to_year\":\"2020\